select *, pickUser.nx_distributer_user_id 'pick_nx_distributer_user_id', pickUser.nx_DIU_wx_nick_name 'pick_nx_DIU_wx_nick_name', pickUser.nx_DIU_wx_avartra_url 'pick_nx_DIU_wx_avartra_url', ds.nx_department_id 'nx_department_id', ds.nx_department_name 'nx_department_name', ds.nx_department_attr_name 'nx_department_attr_name', ds.nx_department_order_code 'nx_department_order_code', ds.nx_department_type 'nx_department_type', ds.nx_department_father_id 'nx_department_father_id', ds.nx_department_is_group_dep 'nx_department_is_group_dep', df.nx_department_id 'dd_nx_department_id', df.nx_department_pick_name 'dd_nx_department_pick_name', df.nx_department_name 'dd_nx_department_name', df.nx_department_attr_name 'dd_nx_department_attr_name', df.nx_department_order_code 'dd_nx_department_order_code', ngds.gb_department_id 'nds_gb_department_id', ngds.gb_department_name 'nds_gb_department_name', ngds.gb_department_attr_name 'nds_gb_department_attr_name', ngds.gb_department_type 'nds_gb_department_type', ngds.gb_department_father_id 'nds_gb_department_father_id', ngds.gb_department_is_group_dep 'nds_gb_department_is_group_dep', ngdf.gb_department_id 'ndf_dd_gb_department_id', ngdf.gb_department_sub_amount 'ndf_dd_gb_department_sub_amount', ngdf.gb_department_name 'ndf_dd_gb_department_name', ngdf.gb_department_attr_name 'ndf_dd_gb_department_attr_name', sell_user.nx_jrdh_user_id 'sell_user_nx_jrdh_user_id', sell_user.nx_jrdh_wx_avartra_url 'sell_user_nx_jrdh_wx_avartra_url', sell_user.nx_jrdh_wx_nick_name 'sell_user_nx_jrdh_wx_nick_name', sell_user.nx_jrdh_url_change 'sell_user_nx_jrdh_url_change', batchDep.nx_department_order_code 'batch_dep_nx_department_name' from nx_distributer_purchase_batch as dpb left join nx_department as batchDep on batchDep.nx_department_id = dpb.nx_DPB_nx_department_father_id left join nx_jrdh_supplier as njs on njs.nx_jrdh_supplier_id = dpb.nx_DPB_supplier_id left join nx_distributer_purchase_goods as dpg on dpg.nx_DPG_batch_id = dpb.nx_distributer_purchase_batch_id left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = dpg.nx_DPG_dis_goods_id left join nx_distributer_father_goods as ndfg on ndfg.nx_distributer_father_goods_id = dg.nx_dg_dfg_goods_grand_id left join nx_distributer_father_goods as great on great.nx_distributer_father_goods_id = ndfg.nx_dfg_fathers_father_id left join nx_goods as ng_great on ng_great.nx_goods_id = great.nx_dfg_nx_goods_id left join nx_goods as ng_ndfg on ng_ndfg.nx_goods_id = ndfg.nx_dfg_nx_goods_id left join nx_goods as ng_dg on ng_dg.nx_goods_id = dg.nx_dg_nx_goods_id left join nx_department_orders as dor on dor.nx_DO_purchase_goods_id = dpg.nx_distributer_purchase_goods_id and dor.nx_DO_status < 3 left join nx_distributer_user as pickUser on pickUser.nx_distributer_user_id = dor.nx_DO_pick_user_id left join nx_department as ds on ds.nx_department_id = dor.nx_DO_department_id left join nx_department as df on df.nx_department_id = ds.nx_department_father_id left join nx_jrdh_user as buy_user on buy_user.nx_jrdh_user_id = dpb.nx_DPB_buy_user_id left join nx_jrdh_user as sell_user on sell_user.nx_jrdh_user_id = dpb.nx_DPB_sell_user_id left join nx_distributer_user as ndu on ndu.nx_distributer_user_id = dpb.nx_DPB_pur_user_id left join gb_department as ngds on ngds.gb_department_id = dor.nx_DO_gb_department_id left join gb_department as ngdf on ngdf.gb_department_id = ngds.gb_department_father_id left join nx_restraunt as nr on nr.nx_restraunt_id = dor.nx_DO_nx_comm_restraunt_id
and nx_DPB_distributer_id = #{disId}
and dpb.nx_DPB_supplier_id = #{supplierId}
and nx_DPB_status < #{status}
and dor.nx_DO_status < #{applyStatus}
and nx_DPB_status = #{equalStatus}
and dor.nx_DO_status < #{orderStatus}
and dor.nx_DO_status = #{equalOrderStatus}
and nx_DPB_status > #{dayuStatus}
and dpb.nx_DPB_pay_type = #{payType}
and dpb.nx_DPB_purchase_type = #{type}
and dpb.nx_DPB_purchase_type > #{typeDayu}
and dpb.nx_DPB_sell_user_id = #{sellerId}
and dpb.nx_DPB_buy_user_id = #{buyerId}
and dpb.nx_DPB_pur_user_id = #{purUserId}
and dpb.nx_DPB_month = #{month}
and dpb.nx_DPB_need_date >= #{startDate}
and dpb.nx_DPB_need_date <= #{stopDate}
and dpb.nx_DPB_need_date = #{equalDate}
and dpb.nx_DPB_year = #{year}
and nx_DPB_purchase_type = #{purchaseType}
order by nx_distributer_purchase_batch_id DESC, COALESCE(ng_great.nx_goods_sort, great.nx_dfg_father_goods_sort), COALESCE(ng_ndfg.nx_goods_sort, ndfg.nx_dfg_father_goods_sort), COALESCE(ng_dg.nx_goods_sort, dg.nx_dg_goods_sort), COALESCE(ng_dg.nx_goods_sons_sort, dg.nx_dg_goods_sons_sort), df.nx_department_id,ds.nx_department_id, ngdf.gb_department_id, ngds.gb_department_id, nr.nx_restraunt_id

