select -- Batch 基本信息 dpb.nx_distributer_purchase_batch_id, dpb.nx_DPB_status, dpb.nx_DPB_pay_type, dpb.nx_DPB_purchase_type, dpb.nx_DPB_supplier_id, dpb.nx_DPB_sell_subtotal, batchDep.nx_department_order_code 'batch_dep_nx_department_name',
-- 买家信息 buy_user.nx_jrdh_user_id, buy_user.nx_jrdh_wx_avartra_url, buy_user.nx_jrdh_wx_nick_name,
-- 卖家信息 sell_user.nx_jrdh_user_id 'sell_user_nx_jrdh_user_id', sell_user.nx_jrdh_wx_avartra_url 'sell_user_nx_jrdh_wx_avartra_url', sell_user.nx_jrdh_wx_nick_name 'sell_user_nx_jrdh_wx_nick_name',
-- 采购商品基本信息 dpg.nx_distributer_purchase_goods_id, dpg.nx_DPG_finish_amount, dpg.nx_DPG_status, dpg.nx_DPG_buy_price, dpg.nx_DPG_buy_quantity, dpg.nx_DPG_buy_subtotal,
-- 商品基本信息 dg.nx_distributer_goods_id, dg.nx_dg_goods_brand, dg.nx_dg_goods_name, dg.nx_dg_goods_standard_weight, dg.nx_dg_goods_standardname,
-- 订单基本信息 dor.nx_department_orders_id, dor.nx_DO_quantity, dor.nx_DO_standard, dor.nx_DO_remark, dor.nx_DO_weight, dor.nx_DO_cost_price, dor.nx_DO_cost_subtotal, dor.nx_DO_distributer_id, dor.nx_DO_collaborative_nx_dis_id, COALESCE(nd_coll.nx_distributer_show_name, nd_coll.nx_distributer_name) as nx_do_collaborative_distributer_name,
-- 部门信息 ds.nx_department_id, ds.nx_department_name, ds.nx_department_order_code, df.nx_department_id 'dd_nx_department_id', df.nx_department_attr_name 'dd_nx_department_attr_name', df.nx_department_order_code 'dd_nx_department_order_code',
-- GB部门信息 ngds.gb_department_id 'nds_gb_department_id', ngds.gb_department_name 'nds_gb_department_name', ngds.gb_department_sub_amount 'nds_gb_department_sub_amount', ngdf.gb_department_id 'ndf_dd_gb_department_id', ngdf.gb_department_name 'ndf_dd_gb_department_name',
-- 餐厅信息 nr.nx_restraunt_id, nr.nx_restraunt_attr_name, nr.nx_restraunt_name
from nx_distributer_purchase_batch as dpb left join nx_department as batchDep on batchDep.nx_department_id = dpb.nx_DPB_nx_department_father_id left join nx_jrdh_user as buy_user on buy_user.nx_jrdh_user_id = dpb.nx_DPB_buy_user_id left join nx_jrdh_user as sell_user on sell_user.nx_jrdh_user_id = dpb.nx_DPB_sell_user_id left join nx_distributer_purchase_goods as dpg on dpg.nx_DPG_batch_id = dpb.nx_distributer_purchase_batch_id left join nx_distributer_goods as dg on dg.nx_distributer_goods_id = dpg.nx_DPG_dis_goods_id left join nx_goods as ng_dg on ng_dg.nx_goods_id = dg.nx_dg_nx_goods_id left join nx_department_orders as dor on dor.nx_DO_purchase_goods_id = dpg.nx_distributer_purchase_goods_id and dor.nx_DO_status < 3 left join nx_distributer as nd_coll on nd_coll.nx_distributer_id = dor.nx_DO_collaborative_nx_dis_id left join nx_department as ds on ds.nx_department_id = dor.nx_DO_department_id left join nx_department as df on df.nx_department_id = ds.nx_department_father_id left join gb_department as ngds on ngds.gb_department_id = dor.nx_DO_gb_department_id left join gb_department as ngdf on ngdf.gb_department_id = ngds.gb_department_father_id left join nx_restraunt as nr on nr.nx_restraunt_id = dor.nx_DO_nx_comm_restraunt_id
and dpb.nx_DPB_distributer_id = #{disId}
and dor.nx_DO_distributer_id = #{disId}
and dpb.nx_DPB_status < #{status}
and dpb.nx_DPB_purchase_type = #{purchaseType}
and dpb.nx_DPB_supplier_id = #{supplierId}
and dpb.nx_DPB_status = #{equalStatus}
and dpb.nx_DPB_status > #{dayuStatus}
and dpb.nx_DPB_sell_user_id = #{sellerId}
and dpb.nx_DPB_buy_user_id = #{buyerId}
order by dpb.nx_distributer_purchase_batch_id DESC, COALESCE(ng_dg.nx_goods_sort, dg.nx_dg_goods_sort), ds.nx_department_id, ngds.gb_department_id, nr.nx_restraunt_id

